// src/components/Hero.jsx
// ─────────────────────────────────────────────
// INSTRUCCIONES PARA EL VÍDEO:
// 1. Copia tu vídeo a la carpeta /public del proyecto
// 2. Renómbralo a: hero-video.mp4
// 3. Listo — aparecerá de fondo automáticamente
// ─────────────────────────────────────────────

import { personal } from '../data/portfolio';

export default function Hero() {
  return (
    <section id="hero" style={s.section}>

      {/* ── Vídeo de fondo ── */}
      <video
        autoPlay
        loop
        muted
        playsInline
        style={s.videoBg}
      >
        <source src="/hero-video.mp4" type="video/mp4" />
      </video>

      {/* Overlay oscuro encima del vídeo — ajusta opacity para más/menos oscuridad */}
      <div style={s.overlay} />

      {/* Grid sutil encima del overlay */}
      <div style={s.bgGrid} />

      {/* ── Contenido ── */}
      <div style={s.content}>

        <div style={s.badge}>
          <span style={s.badgeDot} />
          Available for work
        </div>

        <p style={s.greeting}>Hello, I'm</p>

        <h1 style={s.name}>
          {personal.name.split(' ')[0]}<br />
          <span style={s.nameAccent}>{personal.name.split(' ')[1]}</span>
        </h1>

        <p style={s.role}>{personal.role}</p>
        <p style={s.tagline}>{personal.tagline}</p>

        <p style={s.desc}>
          Desarrollador Web proactivo con experiencia práctica en
          aplicaciones Full Stack en entornos reales. Especializado en{' '}
          <strong style={s.strong}>React</strong>,{' '}
          <strong style={s.strong}>.NET</strong> y{' '}
          <strong style={s.strong}>SQL</strong>.
          Alta capacidad de adaptación y aprendizaje rápido.
        </p>

        <div style={s.actions}>
          <a
            href="#contact"
            style={s.btnPrimary}
            onMouseEnter={e => {
              e.currentTarget.style.background = 'var(--accent2)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = 'var(--accent)';
              e.currentTarget.style.transform = 'none';
            }}
          >
            Get in touch
          </a>
          <a
            href="#experience"
            style={s.btnSecondary}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = 'rgba(255,255,255,0.3)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = 'rgba(255,255,255,0.15)';
              e.currentTarget.style.transform = 'none';
            }}
          >
            View my work ↓
          </a>
        </div>

        {/* Stats */}
        <div style={s.stats}>
          {personal.stats.map((st, i) => (
            <div key={i} style={s.stat}>
              <div style={s.statNum}>
                {st.value.replace(/[^0-9A-Za-z]/g, '')}
                <span style={s.statAccent}>
                  {st.value.match(/[^0-9A-Za-z]/)?.[0] || ''}
                </span>
              </div>
              <div style={s.statLabel}>{st.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* ── Círculo RM a la derecha (decorativo) ── */}
      <div style={s.circleWrap}>
        <div style={s.ringOuter}>
          {[0, 60, 120, 180, 240, 300].map(deg => (
            <div
              key={deg}
              style={{
                ...s.ringDot,
                transform: `rotate(${deg}deg) translateX(159px)`,
              }}
            />
          ))}
        </div>
        <div style={s.ringInner} />
        <div style={s.circle}>
          <span style={s.circleText}>RM</span>
        </div>
        <div style={{ ...s.floatDot, top: '8%',   right: '-10%', width: 10, height: 10 }} />
        <div style={{ ...s.floatDot, bottom: '18%', left: '-8%',  width: 6,  height: 6, opacity: 0.3 }} />
      </div>

    </section>
  );
}

const s = {
  section: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    padding: '120px 5% 80px',
    position: 'relative',
    overflow: 'hidden',
  },

  // Vídeo de fondo
  videoBg: {
    position: 'absolute',
    inset: 0,
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    zIndex: 0,
  },

  // Overlay oscuro — cambia el último número (0.82) para más o menos oscuridad
  overlay: {
    position: 'absolute',
    inset: 0,
    background: 'linear-gradient(to right, rgba(10,10,12,0.92) 45%, rgba(10,10,12,0.65) 100%)',
    zIndex: 1,
  },

  // Grid sutil
  bgGrid: {
    position: 'absolute', inset: 0,
    backgroundImage: `
      linear-gradient(rgba(255,255,255,0.015) 1px, transparent 1px),
      linear-gradient(90deg, rgba(255,255,255,0.015) 1px, transparent 1px)
    `,
    backgroundSize: '56px 56px',
    pointerEvents: 'none',
    zIndex: 2,
  },

  content: {
    position: 'relative',
    zIndex: 3,
    maxWidth: 640,
  },

  badge: {
    display: 'inline-flex', alignItems: 'center', gap: 8,
    background: 'rgba(232,58,58,0.09)',
    border: '1px solid rgba(232,58,58,0.22)',
    color: 'var(--accent2)',
    fontSize: 11, fontWeight: 600,
    letterSpacing: '0.12em', textTransform: 'uppercase',
    padding: '6px 16px', borderRadius: 100,
    marginBottom: 32,
  },
  badgeDot: {
    display: 'inline-block',
    width: 6, height: 6, borderRadius: '50%',
    background: 'var(--accent)',
    animation: 'pulse 2s infinite',
  },

  greeting: {
    fontFamily: 'var(--font-body)',
    fontSize: 20, fontWeight: 300,
    color: 'var(--text2)', marginBottom: 6,
  },

  name: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(56px, 8vw, 92px)',
    fontWeight: 800,
    letterSpacing: '-3px', lineHeight: 1,
    color: 'var(--text)', marginBottom: 16,
  },
  nameAccent: { color: 'var(--accent)' },

  role: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(20px, 3vw, 30px)',
    fontWeight: 500, color: 'var(--text2)',
    letterSpacing: '-0.5px', marginBottom: 6,
  },

  tagline: {
    fontSize: 12, fontWeight: 600,
    letterSpacing: '0.14em', textTransform: 'uppercase',
    color: 'var(--accent)', marginBottom: 28,
  },

  desc: {
    fontSize: 16, fontWeight: 300,
    color: 'var(--text2)', lineHeight: 1.8,
    maxWidth: 500, marginBottom: 44,
  },
  strong: { color: 'var(--text)', fontWeight: 500 },

  actions: { display: 'flex', gap: 14, flexWrap: 'wrap', alignItems: 'center' },
  btnPrimary: {
    background: 'var(--accent)', color: '#fff',
    padding: '14px 32px', borderRadius: 8,
    fontFamily: 'var(--font-body)',
    fontSize: 15, fontWeight: 500,
    textDecoration: 'none', display: 'inline-block',
    transition: 'background 0.2s, transform 0.15s',
    boxShadow: '0 4px 22px rgba(232,58,58,0.28)',
  },
  btnSecondary: {
    background: 'rgba(255,255,255,0.06)',
    backdropFilter: 'blur(8px)',
    color: 'var(--text)',
    border: '1px solid rgba(255,255,255,0.15)',
    padding: '13px 30px', borderRadius: 8,
    fontFamily: 'var(--font-body)',
